#include <stdio.h>

int isPrime(int number) {
    if (number < 2) return 0;

    for (int i = 2; i * i <= number; i++) {
        if (number % i == 0) return 0;
    }
    return 1;
}

int main() {
    printf("1-50 arasindaki asal sayilar:\n");

    int count = 0;
    for (int i = 1; i <= 50; i++) {
        if (isPrime(i)) {
            printf("%d ", i);
            count++;
        }
    }
    printf("\n");

    printf("\nToplam asal sayi adedi: %d\n", count);

    // Tekil kontrol
    int testNumber = 97;
    printf("\n%d asal mi: %s\n", testNumber, isPrime(testNumber) ? "Evet" : "Hayir");

    testNumber = 100;
    printf("%d asal mi: %s\n", testNumber, isPrime(testNumber) ? "Evet" : "Hayir");

    return 0;
}
